selector_to_html = {"a[href=\"#name-selection\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Name selection<a class=\"headerlink\" href=\"#name-selection\" title=\"Link to this heading\">\uf0c1</a></h3><p>Several names were evaluated against PyPI, BCR, and npm before settling on\n<code class=\"docutils literal notranslate\"><span class=\"pre\">tlbox</span></code>:</p>", "a[href=\"#the-tlbox-namespace\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">The <code class=\"docutils literal notranslate\"><span class=\"pre\">tlbox/</span></code> Namespace<a class=\"headerlink\" href=\"#the-tlbox-namespace\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Python<a class=\"headerlink\" href=\"#python\" title=\"Link to this heading\">\uf0c1</a></h3><p><code class=\"docutils literal notranslate\"><span class=\"pre\">tlbox</span></code> is a <a class=\"reference external\" href=\"https://peps.python.org/pep-0420/\">namespace package</a> \u2014 no\n<code class=\"docutils literal notranslate\"><span class=\"pre\">__init__.py</span></code> files are needed. Python 3 resolves the namespace implicitly.</p><p>Imports use the full <code class=\"docutils literal notranslate\"><span class=\"pre\">tlbox.*</span></code> path:</p>", "a[href=\"#why-not-src\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Why not <code class=\"docutils literal notranslate\"><span class=\"pre\">src/</span></code>?<a class=\"headerlink\" href=\"#why-not-src\" title=\"Link to this heading\">\uf0c1</a></h3><p><code class=\"docutils literal notranslate\"><span class=\"pre\">src/</span></code> is a Python packaging convention that prevents accidental imports when\nrunning Python directly from the repo root. In a Bazel repo, imports are managed\nhermetically, so <code class=\"docutils literal notranslate\"><span class=\"pre\">src/</span></code> adds label verbosity (<code class=\"docutils literal notranslate\"><span class=\"pre\">//src/tlbox/...</span></code>) with no\nbenefit.</p>", "a[href=\"#rules-of-thumb\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Rules of Thumb<a class=\"headerlink\" href=\"#rules-of-thumb\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>Where does new code go?</strong></p>", "a[href=\"#directory-map\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Directory Map<a class=\"headerlink\" href=\"#directory-map\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#repository-structure\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Repository Structure<a class=\"headerlink\" href=\"#repository-structure\" title=\"Link to this heading\">\uf0c1</a></h1><h2>Overview<a class=\"headerlink\" href=\"#overview\" title=\"Link to this heading\">\uf0c1</a></h2><p>All project code lives under the <code class=\"docutils literal notranslate\"><span class=\"pre\">tlbox/</span></code> top-level directory. This is a\nlanguage-agnostic namespace \u2014 Python, C++, Rust, hardware, and documentation all\ncoexist under it. The namespace doubles as the Python package name and is\nreserved on PyPI, BCR, and npm for future publishing.</p><p>Build infrastructure, platform definitions, and vendored dependencies live\noutside <code class=\"docutils literal notranslate\"><span class=\"pre\">tlbox/</span></code> at the repo root.</p>", "a[href=\"#overview\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Overview<a class=\"headerlink\" href=\"#overview\" title=\"Link to this heading\">\uf0c1</a></h2><p>All project code lives under the <code class=\"docutils literal notranslate\"><span class=\"pre\">tlbox/</span></code> top-level directory. This is a\nlanguage-agnostic namespace \u2014 Python, C++, Rust, hardware, and documentation all\ncoexist under it. The namespace doubles as the Python package name and is\nreserved on PyPI, BCR, and npm for future publishing.</p><p>Build infrastructure, platform definitions, and vendored dependencies live\noutside <code class=\"docutils literal notranslate\"><span class=\"pre\">tlbox/</span></code> at the repo root.</p>", "a[href=\"#what-stays-outside-tlbox\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">What Stays Outside <code class=\"docutils literal notranslate\"><span class=\"pre\">tlbox/</span></code><a class=\"headerlink\" href=\"#what-stays-outside-tlbox\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#python\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Python<a class=\"headerlink\" href=\"#python\" title=\"Link to this heading\">\uf0c1</a></h3><p><code class=\"docutils literal notranslate\"><span class=\"pre\">tlbox</span></code> is a <a class=\"reference external\" href=\"https://peps.python.org/pep-0420/\">namespace package</a> \u2014 no\n<code class=\"docutils literal notranslate\"><span class=\"pre\">__init__.py</span></code> files are needed. Python 3 resolves the namespace implicitly.</p><p>Imports use the full <code class=\"docutils literal notranslate\"><span class=\"pre\">tlbox.*</span></code> path:</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
